-func TestEnsureSettingsAt_CreatesFile(t *testing.T) {
-	tmpDir := t.TempDir()
-
-	hooksDir := ".copilot"
-	hooksFile := "copilot-instructions.md"
-	settingsPath := filepath.Join(tmpDir, hooksDir, hooksFile)
-
-	if _, err := os.Stat(settingsPath); err == nil {
